// Strict v3 env contract preflight. Fail fast with missing ENV NAMES only.
const config = {
  appUrl: String($env.APP_URL || '').trim(),
  webhookSecret: String($env.N8N_WEBHOOK_SECRET || '').trim(),
  anthropicApiKey: String($env.ANTHROPIC_API_KEY || '').trim(),
  adzunaAppId: String($env.ADZUNA_APP_ID || '').trim(),
  adzunaAppKey: String($env.ADZUNA_APP_KEY || '').trim(),
  jsearchApiKey: String($env.JSEARCH_API_KEY || '').trim(),
  joobleApiKey: String($env.JOOBLE_API_KEY || '').trim(),
  reedApiKey: String($env.REED_API_KEY || '').trim(),
  v3CanaryUserIds: String($env.V3_CANARY_USER_IDS || '').trim(),
  v3CanarySampleRate: String($env.V3_CANARY_SAMPLE_RATE || '0').trim(),
  v3JobCapPerUser: String($env.V3_JOB_CAP_PER_USER || '').trim(),
  v3TailorCapPerUser: String($env.V3_TAILOR_CAP_PER_USER || '').trim(),
  v3LlmPaceMs: String($env.V3_LLM_PACE_MS || '').trim(),
  v3MaxRetries: String($env.V3_MAX_RETRIES || '').trim(),
  v3RetryBaseMs: String($env.V3_RETRY_BASE_MS || '').trim(),
  v3RetryCapMs: String($env.V3_RETRY_CAP_MS || '').trim()
};

const required = {
  APP_URL: config.appUrl,
  N8N_WEBHOOK_SECRET: config.webhookSecret,
  ANTHROPIC_API_KEY: config.anthropicApiKey,
  ADZUNA_APP_ID: config.adzunaAppId,
  ADZUNA_APP_KEY: config.adzunaAppKey,
  JSEARCH_API_KEY: config.jsearchApiKey,
  JOOBLE_API_KEY: config.joobleApiKey,
  REED_API_KEY: config.reedApiKey,
  V3_JOB_CAP_PER_USER: config.v3JobCapPerUser,
  V3_TAILOR_CAP_PER_USER: config.v3TailorCapPerUser,
  V3_LLM_PACE_MS: config.v3LlmPaceMs,
  V3_MAX_RETRIES: config.v3MaxRetries,
  V3_RETRY_BASE_MS: config.v3RetryBaseMs,
  V3_RETRY_CAP_MS: config.v3RetryCapMs
};

const missing = Object.entries(required)
  .filter(([_, value]) => !String(value || '').trim())
  .map(([name]) => name);

if (missing.length > 0) {
  throw new Error('MISSING_ENV_NAMES:' + missing.join(','));
}

return [{
  json: {
    config: {
      ...config,
      v3CanarySampleRate: Number(config.v3CanarySampleRate || 0),
      v3JobCapPerUser: Number(config.v3JobCapPerUser || 0),
      v3TailorCapPerUser: Number(config.v3TailorCapPerUser || 0),
      v3LlmPaceMs: Number(config.v3LlmPaceMs || 0),
      v3MaxRetries: Number(config.v3MaxRetries || 0),
      v3RetryBaseMs: Number(config.v3RetryBaseMs || 0),
      v3RetryCapMs: Number(config.v3RetryCapMs || 0)
    }
  }
}];

const input = $input.first().json || {};
const config = input.config || {};
const runId = 'disc_v3_' + String($execution.id || Date.now());

function slotIdForNow() {
  const now = new Date();
  const slotHour = Math.floor(now.getUTCHours() / 4) * 4;
  const slot = new Date(Date.UTC(
    now.getUTCFullYear(),
    now.getUTCMonth(),
    now.getUTCDate(),
    slotHour,
    0,
    0,
    0
  ));
  return slot.toISOString();
}

function parseCsv(raw) {
  return String(raw || '').split(',').map((v) => v.trim()).filter(Boolean);
}

return [{
  json: {
    config,
    runId,
    slotId: slotIdForNow(),
    workflowId: 'job-discovery-pipeline-v3',
    appWebhookUrl: String(config.appUrl || '').replace(/\/$/, '') + '/api/webhooks/n8n',
    canaryAllowlist: parseCsv(config.v3CanaryUserIds),
    summary: {
      status: 'ok',
      runId,
      usersSeen: 0,
      usersCanary: 0,
      usersProcessed: 0,
      usersFailed: 0,
      persistedApplications: 0
    }
  }
}];

const base = $('Initialize Discovery Context v3').first().json || {};
const lock = $input.first().json || {};

const acquired = Boolean(lock && lock.acquired);
const lockId = acquired ? String(lock.lockId || '') : '';

return [{
  json: {
    ...base,
    lockAcquired: acquired,
    lockId,
    lockExpiresAt: lock.expiresAt || null,
    summary: {
      ...(base.summary || {}),
      slotId: base.slotId,
      status: acquired ? 'ok' : 'skipped_lock_not_acquired'
    }
  }
}];

const base = $input.first().json || {};
return [{
  json: {
    ...(base.summary || {}),
    slotId: base.slotId,
    runId: base.runId,
    lockAcquired: false,
    lockReleased: false,
    reason: 'lock_not_acquired'
  }
}];

const base = $('Parse Lock Result v3').first().json || {};
const payload = $input.first().json || {};
const users = Array.isArray(payload.users) ? payload.users : [];
const allowlist = new Set(Array.isArray(base.canaryAllowlist) ? base.canaryAllowlist : []);

const canaryUsers = users.filter((user) => {
  if (!user || typeof user !== 'object') return false;
  const userId = String(user.id || '').trim();
  if (!userId) return false;
  if (allowlist.size === 0) return false;
  return allowlist.has(userId);
});

if (canaryUsers.length === 0) {
  return [{
    json: {
      ...base,
      user: null,
      userId: null,
      usersSeen: users.length,
      usersCanary: 0
    }
  }];
}

return canaryUsers.map((user) => {
  const userId = String(user.id || '').trim();
  return {
    json: {
      ...base,
      user,
      userId,
      usersSeen: users.length,
      usersCanary: canaryUsers.length
    }
  };
});

const item = $input.first().json || {};
return [{
  json: {
    runId: item.runId,
    slotId: item.slotId,
    lockId: item.lockId,
    lockAcquired: true,
    usersSeen: Number(item.usersSeen || 0),
    usersCanary: 0,
    usersProcessed: 0,
    usersFailed: 0,
    persistedApplications: 0,
    status: 'no_canary_users'
  }
}];

const userCtx = $('Prepare Canary Users v3').item.json || {};
const payload = $input.item.json || {};
const jobs = Array.isArray(payload.jobs) ? payload.jobs : [];
const user = userCtx.user || {};
const userId = String(userCtx.userId || '').trim();

const dedupe = new Set();
const normalized = [];

for (const rawJob of jobs) {
  if (!rawJob || typeof rawJob !== 'object') continue;
  const title = String(rawJob.title || '').trim();
  const description = String(rawJob.description || '').trim();
  const source = String(rawJob.source || 'manual').trim() || 'manual';
  const externalId = String(rawJob.externalId || rawJob.url || '').trim();
  if (!title || !description || !externalId) continue;
  const key = (source + ':' + externalId).toLowerCase();
  if (dedupe.has(key)) continue;
  dedupe.add(key);
  normalized.push({
    externalId,
    title,
    company: String(rawJob.company || 'Unknown Company').trim() || 'Unknown Company',
    location: String(rawJob.location || 'Not specified').trim() || 'Not specified',
    description,
    source,
    url: String(rawJob.url || '').trim(),
    salary: rawJob.salary || null,
    postedAt: rawJob.postedAt || null,
    userId,
    masterCvText: String(user.masterCvText || '')
  });
}

const cap = Math.max(0, Number(userCtx.config && userCtx.config.v3JobCapPerUser ? userCtx.config.v3JobCapPerUser : 0));
const jobsCapped = normalized.slice(0, cap);

if (jobsCapped.length === 0) {
  return {
  json: {
      ...userCtx,
      hasJobs: false,
      jobsCapped: [],
      applicationsBase: []
    }
  };
}

const scoringPrompt = [
  'Return ONLY a JSON array:',
  '[{"idx":0,"compatibility_score":0-100,"ats_keywords":[],"matching_strengths":[],"gaps":[],"recommendation":"apply|stretch|skip"}]',
  'Candidate CV:',
  String(user.masterCvText || '').slice(0, 7000),
  'Jobs:',
  JSON.stringify(jobsCapped.map((job, idx) => ({
    idx,
    title: job.title,
    company: job.company,
    description: String(job.description || '').slice(0, 2200)
  })))
].join('\n');

return {
  json: {
    ...userCtx,
    hasJobs: true,
    jobsCapped,
    scoringPrompt
  }
};

const item = $input.first().json || {};
return [{
  json: {
    runId: item.runId,
    slotId: item.slotId,
    lockId: item.lockId,
    usersSeen: Number(item.usersSeen || 0),
    usersCanary: Number(item.usersCanary || 0),
    userId: item.userId,
    processed: true,
    failed: false,
    persistedCount: 0,
    reason: 'no_jobs_after_normalization'
  }
}];

const prev = $('Normalize/Dedupe Jobs v3').item.json || {};
const resp = $input.item.json || {};

function parseJsonArray(text) {
  const raw = String(text || '');
  const start = raw.indexOf('[');
  const end = raw.lastIndexOf(']');
  if (start < 0 || end <= start) return null;
  try {
    const parsed = JSON.parse(raw.slice(start, end + 1));
    return Array.isArray(parsed) ? parsed : null;
  } catch {
    return null;
  }
}

const text = resp.content && resp.content[0] ? String(resp.content[0].text || '') : '';
const scoredRows = parseJsonArray(text);
if (!Array.isArray(scoredRows)) {
  return {
  json: {
      ...prev,
      scoreParseOk: false,
      scoreReasonCode: 'SCORING_PARSE_FAILURE'
    }
  };
}

const scoreByIdx = new Map();
for (const row of scoredRows) {
  if (!row || typeof row !== 'object') continue;
  const idx = Number(row.idx);
  if (!Number.isInteger(idx)) continue;
  scoreByIdx.set(idx, {
    compatibilityScore: Number(row.compatibility_score || 0),
    atsKeywords: Array.isArray(row.ats_keywords) ? row.ats_keywords.slice(0, 12) : [],
    matchingStrengths: Array.isArray(row.matching_strengths) ? row.matching_strengths.slice(0, 6) : [],
    gaps: Array.isArray(row.gaps) ? row.gaps.slice(0, 6) : [],
    recommendation: String(row.recommendation || 'skip')
  });
}

const scoredJobs = (Array.isArray(prev.jobsCapped) ? prev.jobsCapped : []).map((job, idx) => {
  const score = scoreByIdx.get(idx) || {
    compatibilityScore: 0,
    atsKeywords: [],
    matchingStrengths: [],
    gaps: [],
    recommendation: 'skip'
  };
  return {
    ...job,
    compatibilityScore: Math.max(0, Math.min(100, Number(score.compatibilityScore || 0))),
    atsKeywords: score.atsKeywords,
    matchingStrengths: score.matchingStrengths,
    gaps: score.gaps,
    recommendation: score.recommendation
  };
});

const threshold = 70;
const tailorCap = Math.max(0, Number(prev.config && prev.config.v3TailorCapPerUser ? prev.config.v3TailorCapPerUser : 0));
const candidatesToTailor = scoredJobs.filter((job) => Number(job.compatibilityScore || 0) >= threshold).slice(0, tailorCap);

const applicationsBase = scoredJobs.map((job) => ({
  ...job,
  tailoredCvMarkdown: null,
  coverLetterMarkdown: null,
  status: 'discovered'
}));

return {
  json: {
    ...prev,
    scoreParseOk: true,
    scoredJobs,
    candidatesToTailor,
    applicationsBase,
    hasTailorCandidates: candidatesToTailor.length > 0
  }
};

const item = $input.first().json || {};
return [{
  json: {
    appWebhookUrl: item.appWebhookUrl,
    runId: item.runId,
    webhookSecret: item.config ? item.config.webhookSecret : '',
    userId: item.userId,
    reasonCode: item.scoreReasonCode || 'SCORING_PARSE_FAILURE',
    workflowErrorData: {
      workflowId: item.workflowId || 'job-discovery-pipeline-v3',
      nodeName: 'Parse Scores v3',
      errorType: item.scoreReasonCode || 'SCORING_PARSE_FAILURE',
      message: 'Parse Scores v3:' + String(item.scoreReasonCode || 'SCORING_PARSE_FAILURE'),
      payload: {
        runId: item.runId,
        slotId: item.slotId,
        userId: item.userId,
        reasonCode: item.scoreReasonCode || 'SCORING_PARSE_FAILURE'
      },
      userId: item.userId
    },
    lockId: item.lockId,
    usersSeen: Number(item.usersSeen || 0),
    usersCanary: Number(item.usersCanary || 0)
  }
}];

const item = $input.first().json || {};
return [{
  json: {
    ...item,
    applicationsFinal: Array.isArray(item.applicationsBase) ? item.applicationsBase : []
  }
}];

const item = $input.item.json || {};
const candidates = Array.isArray(item.candidatesToTailor) ? item.candidatesToTailor : [];
const masterCvText = String(item.user && item.user.masterCvText ? item.user.masterCvText : '');

const tailorPrompt = [
  'Return ONLY a JSON array:',
  '[{"idx":0,"tailored_cv_markdown":"...","motivation_letter_markdown":"..."}]',
  'Never fabricate candidate facts. Use only candidate-provided information.',
  'Candidate CV:',
  masterCvText.slice(0, 7000),
  'Jobs to tailor:',
  JSON.stringify(candidates.map((job, idx) => ({
    idx,
    title: job.title,
    company: job.company,
    atsKeywords: Array.isArray(job.atsKeywords) ? job.atsKeywords : [],
    description: String(job.description || '').slice(0, 3500)
  })))
].join('\n');

return {
  json: {
    ...item,
    tailorPrompt,
    candidatesToTailor: candidates
  }
};

const prev = $('Build Tailor Prompt Batch v3').item.json || {};
const resp = $input.item.json || {};

function parseJsonArray(text) {
  const raw = String(text || '');
  const start = raw.indexOf('[');
  const end = raw.lastIndexOf(']');
  if (start < 0 || end <= start) return null;
  try {
    const parsed = JSON.parse(raw.slice(start, end + 1));
    return Array.isArray(parsed) ? parsed : null;
  } catch {
    return null;
  }
}

const text = resp.content && resp.content[0] ? String(resp.content[0].text || '') : '';
const tailoredRows = parseJsonArray(text);
if (!Array.isArray(tailoredRows)) {
  return {
  json: {
      ...prev,
      tailorParseOk: false,
      tailorReasonCode: 'TAILORING_PARSE_FAILURE'
    }
  };
}

const tailoredByIdx = new Map();
for (const row of tailoredRows) {
  if (!row || typeof row !== 'object') continue;
  const idx = Number(row.idx);
  if (!Number.isInteger(idx)) continue;
  tailoredByIdx.set(idx, {
    tailoredCvMarkdown: String(row.tailored_cv_markdown || ''),
    coverLetterMarkdown: String(row.motivation_letter_markdown || '')
  });
}

const candidateIndex = new Map();
(prev.candidatesToTailor || []).forEach((job, idx) => {
  candidateIndex.set((String(job.source || 'manual') + ':' + String(job.externalId || '')).toLowerCase(), idx);
});

const applicationsFinal = (Array.isArray(prev.applicationsBase) ? prev.applicationsBase : []).map((application) => {
  const key = (String(application.source || 'manual') + ':' + String(application.externalId || '')).toLowerCase();
  const idx = candidateIndex.get(key);
  if (idx === undefined) {
    return application;
  }
  const tailored = tailoredByIdx.get(idx) || { tailoredCvMarkdown: '', coverLetterMarkdown: '' };
  return {
    ...application,
    tailoredCvMarkdown: tailored.tailoredCvMarkdown,
    coverLetterMarkdown: tailored.coverLetterMarkdown,
    status: tailored.tailoredCvMarkdown ? 'tailored' : 'discovered'
  };
});

return {
  json: {
    ...prev,
    tailorParseOk: true,
    applicationsFinal
  }
};

const item = $input.first().json || {};
return [{
  json: {
    appWebhookUrl: item.appWebhookUrl,
    runId: item.runId,
    webhookSecret: item.config ? item.config.webhookSecret : '',
    userId: item.userId,
    reasonCode: item.tailorReasonCode || 'TAILORING_PARSE_FAILURE',
    workflowErrorData: {
      workflowId: item.workflowId || 'job-discovery-pipeline-v3',
      nodeName: 'Parse Tailor Batch v3',
      errorType: item.tailorReasonCode || 'TAILORING_PARSE_FAILURE',
      message: 'Parse Tailor Batch v3:' + String(item.tailorReasonCode || 'TAILORING_PARSE_FAILURE'),
      payload: {
        runId: item.runId,
        slotId: item.slotId,
        userId: item.userId,
        reasonCode: item.tailorReasonCode || 'TAILORING_PARSE_FAILURE'
      },
      userId: item.userId
    },
    lockId: item.lockId,
    usersSeen: Number(item.usersSeen || 0),
    usersCanary: Number(item.usersCanary || 0)
  }
}];

const item = $input.item.json || {};
const applicationsFinal = Array.isArray(item.applicationsFinal)
  ? item.applicationsFinal
  : (Array.isArray(item.applicationsBase) ? item.applicationsBase : []);

const userId = String(item.userId || '').trim();
const slotId = String(item.slotId || '').trim();
const idempotencyKey = 'disc_v3:' + slotId + ':' + userId;

return {
  json: {
    ...item,
    applicationsFinal,
    idempotencyKey,
    skipPersist: !userId || applicationsFinal.length === 0
  }
};

const source = $input.item.json || {};
let base = source;

if (source && source.appWebhookUrl && source.config) {
  base = source;
} else if ($('Prepare Persist Payload v3').item && $('Prepare Persist Payload v3').item.json) {
  base = $('Prepare Persist Payload v3').item.json;
} else if ($('Normalize/Dedupe Jobs v3').item && $('Normalize/Dedupe Jobs v3').item.json) {
  base = $('Normalize/Dedupe Jobs v3').item.json;
}

const isFailure = String(base.reasonCode || '').includes('FAILURE') || String(base.reason || '').includes('FAILURE');
const persistedCount = Array.isArray(base.applicationsFinal) && !base.skipPersist ? base.applicationsFinal.length : 0;

return {
  json: {
    runId: base.runId,
    slotId: base.slotId,
    lockId: base.lockId,
    usersSeen: Number(base.usersSeen || 0),
    usersCanary: Number(base.usersCanary || 0),
    userId: base.userId || null,
    processed: Boolean(base.userId),
    failed: Boolean(isFailure),
    persistedCount,
    reason: base.reason || null,
    reasonCode: base.reasonCode || null
  }
};

const items = $input.all();
const lock = $('Parse Lock Result v3').first().json || {};

let usersProcessed = 0;
let usersFailed = 0;
let persistedApplications = 0;
let usersSeen = 0;
let usersCanary = 0;

for (const item of items) {
  const row = item.json || {};
  usersSeen = Math.max(usersSeen, Number(row.usersSeen || 0));
  usersCanary = Math.max(usersCanary, Number(row.usersCanary || 0));
  if (row.processed) usersProcessed += 1;
  if (row.failed) usersFailed += 1;
  persistedApplications += Number(row.persistedCount || 0);
}

return [{
  json: {
    runId: lock.runId,
    slotId: lock.slotId,
    lockId: lock.lockId,
    lockAcquired: true,
    usersSeen,
    usersCanary,
    usersProcessed,
    usersFailed,
    persistedApplications,
    status: usersFailed > 0 ? 'completed_with_user_errors' : 'ok'
  }
}];

const summary = $input.first().json || {};
return [{
  json: {
    ...summary,
    completedAt: new Date().toISOString()
  }
}];
